1	<!DOCTYPE html>
2	<html lang="ko">
3	<head>
4	<meta charset="UTF-8">
5	<meta name="viewport" content="width=device-width, initial-scale=1.0">
6	<title>상담 이력 상세</title>
7	<style>
8	  * { box-sizing: border-box; margin: 0; padding: 0; }
9	  body {
10	    font-family: '맑은 고딕', 'Malgun Gothic', sans-serif;
11	    font-size: 13px;
12	    background: rgba(0,0,0,0.4);
13	    display: flex;
14	    align-items: center;
15	    justify-content: center;
16	    min-height: 100vh;
17	  }
18	
19	  /* ── 팝업 컨테이너 ── */
20	  .popup {
21	    background: #fff;
22	    border-radius: 6px;
23	    box-shadow: 0 4px 24px rgba(0,0,0,0.3);
24	    width: 980px;
25	    max-height: 90vh;
26	    overflow-y: auto;
27	    display: flex;
28	    flex-direction: column;
29	  }
30	
31	  /* ── 헤더 ── */
32	  .popup-header {
33	    display: flex;
34	    align-items: center;
35	    justify-content: space-between;
36	    padding: 10px 16px;
37	    background: #2c4a7c;
38	    color: #fff;
39	    border-radius: 6px 6px 0 0;
40	    font-size: 14px;
41	    font-weight: bold;
42	    flex-shrink: 0;
43	  }
44	  .popup-header .close-btn {
45	    cursor: pointer;
46	    font-size: 18px;
47	    line-height: 1;
48	    color: #fff;
49	    background: none;
50	    border: none;
51	    padding: 0 4px;
52	  }
53	
54	  /* ── 본문 ── */
55	  .popup-body {
56	    padding: 12px 14px;
57	    display: grid;
58	    grid-template-columns: 1fr 1fr;
59	    gap: 10px;
60	  }
61	
62	  /* ── 섹션 공통 ── */
63	  .section {
64	    border: 1px solid #d0d5de;
65	    border-radius: 4px;
66	    overflow: hidden;
67	  }
68	  .section-title {
69	    background: #f0f3f8;
70	    border-bottom: 1px solid #d0d5de;
71	    padding: 5px 10px;
72	    font-weight: bold;
73	    font-size: 12px;
74	    color: #333;
75	  }
76	  .section-body {
77	    padding: 8px 10px;
78	  }
79	
80	  /* ── 고객 기본정보 (한 줄) ── */
81	  .customer-inline {
82	    display: flex;
83	    align-items: center;
84	    gap: 10px;
85	    flex-wrap: wrap;
86	    padding: 7px 10px;
87	  }
88	  .customer-inline .name {
89	    font-weight: bold;
90	    font-size: 14px;
91	    color: #2c4a7c;
92	  }
93	  .customer-inline .divider {
94	    color: #bbb;
95	    font-size: 13px;
96	  }
97	  .customer-inline .info-chip {
98	    background: #f0f3f8;
99	    border: 1px solid #d0d5de;
100	    border-radius: 3px;
101	    padding: 2px 7px;
102	    font-size: 12px;
103	    color: #444;
104	  }
105	  .customer-inline .info-label {
106	    font-size: 11px;
107	    color: #888;
108	    margin-right: 3px;
109	  }
110	
111	  /* ── 상담 유형 테이블 ── */
112	  .type-table {
113	    width: 100%;
114	    border-collapse: collapse;
115	    font-size: 12px;
116	  }
117	  .type-table th {
118	    background: #f5f7fb;
119	    color: #555;
120	    font-weight: bold;
121	    text-align: center;
122	    padding: 4px 6px;
123	    border-bottom: 1px solid #e0e3eb;
124	    width: 28px;
125	  }
126	  .type-table td {
127	    padding: 5px 8px;
128	    border-bottom: 1px solid #eef0f5;
129	    color: #333;
130	    font-size: 12.5px;
131	  }
132	  .type-table tr:last-child td { border-bottom: none; }
133	  .type-table .rank {
134	    text-align: center;
135	    color: #e05a2b;
136	    font-weight: bold;
137	  }
138	  .type-table .type-link {
139	    color: #2c4a7c;
140	    text-decoration: none;
141	  }
142	  .type-table .type-link:hover { text-decoration: underline; }
143	
144	  /* ── 핵심 문장 ── */
145	  .sentence-table {
146	    width: 100%;
147	    border-collapse: collapse;
148	    font-size: 12px;
149	  }
150	  .sentence-table th {
151	    background: #f5f7fb;
152	    color: #555;
153	    font-weight: bold;
154	    text-align: center;
155	    padding: 4px 6px;
156	    border-bottom: 1px solid #e0e3eb;
157	    width: 28px;
158	  }
159	  .sentence-table td {
160	    padding: 5px 8px;
161	    border-bottom: 1px solid #eef0f5;
162	    color: #333;
163	    font-size: 12.5px;
164	  }
165	  .sentence-table tr:last-child td { border-bottom: none; }
166	  .sentence-table .rank {
167	    text-align: center;
168	    color: #e05a2b;
169	    font-weight: bold;
170	  }
171	
172	  /* ── 키워드 현황 탭 ── */
173	  .kw-tabs {
174	    display: flex;
175	    gap: 3px;
176	    padding: 6px 8px 0;
177	    background: #f7f9fc;
178	    border-bottom: 1px solid #d0d5de;
179	  }
180	  .kw-tab {
181	    padding: 4px 10px;
182	    border: 1px solid #ccc;
183	    border-bottom: none;
184	    border-radius: 3px 3px 0 0;
185	    background: #e8edf5;
186	    cursor: pointer;
187	    font-size: 12px;
188	    color: #555;
189	    transition: background 0.15s;
190	  }
191	  .kw-tab.active {
192	    background: #fff;
193	    border-color: #2c4a7c;
194	    color: #2c4a7c;
195	    font-weight: bold;
196	    border-bottom: 1px solid #fff;
197	    margin-bottom: -1px;
198	  }
199	  .kw-tab:hover:not(.active) { background: #dce5f0; }
200	
201	  /* ── 키워드 테이블 ── */
202	  .kw-table {
203	    width: 100%;
204	    border-collapse: collapse;
205	    font-size: 12px;
206	  }
207	  .kw-table th {
208	    background: #f5f7fb;
209	    color: #555;
210	    font-weight: bold;
211	    text-align: center;
212	    padding: 4px 8px;
213	    border-bottom: 1px solid #e0e3eb;
214	  }
215	  .kw-table td {
216	    padding: 4px 8px;
217	    border-bottom: 1px solid #eef0f5;
218	    text-align: center;
219	    color: #333;
220	  }
221	  .kw-table tr:last-child td { border-bottom: none; }
222	  .kw-table .rank { color: #e05a2b; font-weight: bold; }
223	  .kw-table .kw-word { color: #2c4a7c; }
224	
225	  /* 이슈 탭: 편집 버튼 */
226	  .kw-panel { display: none; }
227	  .kw-panel.active { display: block; }
228	
229	  .issue-tag-area {
230	    padding: 8px 10px;
231	    min-height: 40px;
232	    display: flex;
233	    flex-wrap: wrap;
234	    gap: 5px;
235	    align-items: center;
236	  }
237	  .issue-tag {
238	    background: #e8f0fe;
239	    border: 1px solid #aac4f5;
240	    border-radius: 12px;
241	    padding: 3px 8px 3px 10px;
242	    font-size: 12px;
243	    color: #2c4a7c;
244	    display: inline-flex;
245	    align-items: center;
246	    gap: 4px;
247	  }
248	  .issue-tag .del-btn {
249	    cursor: pointer;
250	    color: #888;
251	    font-size: 14px;
252	    line-height: 1;
253	    background: none;
254	    border: none;
255	    padding: 0 1px;
256	  }
257	  .issue-tag .del-btn:hover { color: #e05a2b; }
258	  .issue-input-row {
259	    display: flex;
260	    gap: 5px;
261	    padding: 6px 10px 8px;
262	    border-top: 1px solid #eef0f5;
263	  }
264	  .issue-input-row input {
265	    flex: 1;
266	    padding: 4px 8px;
267	    border: 1px solid #ccc;
268	    border-radius: 3px;
269	    font-size: 12px;
270	    outline: none;
271	  }
272	  .issue-input-row input:focus { border-color: #2c4a7c; }
273	  .issue-input-row button {
274	    padding: 4px 10px;
275	    background: #2c4a7c;
276	    color: #fff;
277	    border: none;
278	    border-radius: 3px;
279	    font-size: 12px;
280	    cursor: pointer;
281	  }
282	  .issue-input-row button:hover { background: #1e3460; }
283	
284	  /* ── 상담 내용 ── */
285	  .consult-text {
286	    font-size: 12px;
287	    line-height: 1.6;
288	    color: #333;
289	    max-height: 80px;
290	    overflow-y: auto;
291	    padding: 6px 10px;
292	  }
293	  .consult-text .highlight { color: #e05a2b; font-weight: bold; }
294	
295	  /* ── 발화 요약 ── */
296	  .summary-box {
297	    font-size: 12px;
298	    color: #333;
299	    line-height: 1.7;
300	    padding: 8px 12px;
301	    min-height: 60px;
302	    max-height: 120px;
303	    overflow-y: auto;
304	    background: #fafbfd;
305	  }
306	
307	  /* ── 상담 평가 ── */
308	  .eval-area {
309	    padding: 8px 10px;
310	    display: flex;
311	    gap: 12px;
312	    align-items: flex-start;
313	  }
314	  .eval-signal {
315	    display: flex;
316	    flex-direction: column;
317	    align-items: center;
318	    gap: 4px;
319	    flex-shrink: 0;
320	    min-width: 64px;
321	  }
322	  .traffic-light {
323	    width: 32px;
324	    height: 80px;
325	    background: #222;
326	    border-radius: 16px;
327	    display: flex;
328	    flex-direction: column;
329	    align-items: center;
330	    justify-content: space-around;
331	    padding: 6px 4px;
332	    box-shadow: 0 2px 6px rgba(0,0,0,0.4);
333	  }
334	  .light {
335	    width: 18px;
336	    height: 18px;
337	    border-radius: 50%;
338	    background: #333;
339	    transition: background 0.3s, box-shadow 0.3s;
340	  }
341	  /* 위험 = 빨강 */
342	  .status-danger  .light-red    { background: #ff3b30; box-shadow: 0 0 8px #ff3b30; }
343	  /* 미흡 = 주황 */
344	  .status-poor    .light-orange { background: #ff9500; box-shadow: 0 0 8px #ff9500; }
345	  /* 보통 = 노랑 */
346	  .status-normal  .light-yellow { background: #ffcc00; box-shadow: 0 0 8px #ffcc00; }
347	  /* 양호 = 연두 */
348	  .status-good    .light-lime   { background: #34c759; box-shadow: 0 0 8px #34c759; }
349	  /* 우수 = 파랑/청록 */
350	  .status-excellent .light-blue { background: #007aff; box-shadow: 0 0 8px #007aff; }
351	
352	  .eval-label {
353	    font-size: 11px;
354	    font-weight: bold;
355	    padding: 2px 8px;
356	    border-radius: 10px;
357	    margin-top: 2px;
358	  }
359	  .status-danger    .eval-label { background: #ffe5e3; color: #c0392b; }
360	  .status-poor      .eval-label { background: #fff3e0; color: #e67e22; }
361	  .status-normal    .eval-label { background: #fffce0; color: #b8860b; }
362	  .status-good      .eval-label { background: #eafaf1; color: #27ae60; }
363	  .status-excellent .eval-label { background: #e5f0ff; color: #1a6bc4; }
364	
365	  .eval-reason {
366	    flex: 1;
367	  }
368	  .eval-reason .reason-title {
369	    font-size: 11px;
370	    font-weight: bold;
371	    color: #666;
372	    margin-bottom: 4px;
373	  }
374	  .eval-reason ul {
375	    padding-left: 14px;
376	    margin: 0;
377	  }
378	  .eval-reason ul li {
379	    font-size: 12px;
380	    color: #333;
381	    line-height: 1.6;
382	    margin-bottom: 2px;
383	  }
384	
385	  /* ── 푸터 ── */
386	  .popup-footer {
387	    display: flex;
388	    justify-content: center;
389	    padding: 10px 14px 14px;
390	    flex-shrink: 0;
391	  }
392	  .btn-confirm {
393	    padding: 7px 40px;
394	    background: #2c4a7c;
395	    color: #fff;
396	    border: none;
397	    border-radius: 4px;
398	    font-size: 13px;
399	    font-weight: bold;
400	    cursor: pointer;
401	  }
402	  .btn-confirm:hover { background: #1e3460; }
403	
404	  /* ── 좌/우 컬럼 스팬 ── */
405	  .col-left { display: flex; flex-direction: column; gap: 8px; }
406	  .col-right { display: flex; flex-direction: column; gap: 8px; }
407	</style>
