644	/* 이슈 태그 추가 */
645	function addIssueTag() {
646	  const input = document.getElementById('issueInput');
647	  const val = input.value.trim();
648	  if (!val) return;
649	  const area = document.getElementById('issueTagArea');
650	  const tag = document.createElement('span');
651	  tag.className = 'issue-tag';
652	  tag.innerHTML = val + ' <button class="del-btn" onclick="removeTag(this)">×</button>';
653	  area.appendChild(tag);
654	  input.value = '';
655	  input.focus();
656	}
657	
658	/* 이슈 태그 삭제 */
659	function removeTag(btn) {
660	  btn.closest('.issue-tag').remove();
661	}
