554	<script>
555	function switchTab(tabEl, panelId) {
556	  document.querySelectorAll('.kw-tab').forEach(t => t.classList.remove('active'));
557	  document.querySelectorAll('.kw-panel').forEach(p => p.classList.remove('active'));
558	  tabEl.classList.add('active');
559	  document.getElementById(panelId).classList.add('active');
560	}
561	
562	function addIssueTag() {
563	  const input = document.getElementById('issueInput');
564	  const val = input.value.trim();
565	  if (!val) return;
566	  const area = document.getElementById('issueTagArea');
567	  const tag = document.createElement('span');
568	  tag.className = 'issue-tag';
569	  tag.innerHTML = val + ' <button class="del-btn" onclick="removeTag(this)">×</button>';
570	  area.appendChild(tag);
571	  input.value = '';
572	  input.focus();
573	}
574	
575	function removeTag(btn) {
576	  btn.closest('.issue-tag').remove();
577	}
578	</script>
