/* 발화 요약 인라인 편집 */
function startEdit(el) {
  el.contentEditable = 'true';
  el.focus();
  // 커서를 텍스트 끝으로
  const range = document.createRange();
  range.selectNodeContents(el);
  range.collapse(false);
  const sel = window.getSelection();
  sel.removeAllRanges();
  sel.addRange(range);
  // 힌트 텍스트 변경
  const hint = el.previousElementSibling;
  if (hint && hint.classList.contains('summary-edit-hint')) {
    hint.textContent = 'Enter 또는 외부 클릭으로 저장';
    hint.style.color = '#e09000';
  }
}

function endEdit(el) {
  el.contentEditable = 'false';
  const hint = el.previousElementSibling;
  if (hint && hint.classList.contains('summary-edit-hint')) {
    hint.textContent = '더블클릭하여 편집';
    hint.style.color = '';
  }
}

// 편집 중 Enter → 저장(blur), Escape → 취소
document.addEventListener('keydown', function(e) {
  const el = document.activeElement;
  if (!el.classList.contains('summary-text')) return;
  if (e.key === 'Enter' && !e.shiftKey) {
    e.preventDefault();
    el.blur();
  } else if (e.key === 'Escape') {
    el.blur();
  }
});

