document.addEventListener('DOMContentLoaded', () => {
  document.querySelectorAll('.summary-text[data-md]').forEach(el => {
    el.innerHTML = marked.parse(el.dataset.md);
  });
});

function startEdit(el) {
  // 현재 마크다운 원문을 편집 영역에 표시
  el.textContent = el.dataset.md || '';
  el.contentEditable = 'true';
  el.focus();
  // 커서 끝으로
  const range = document.createRange();
  range.selectNodeContents(el);
  range.collapse(false);
  const sel = window.getSelection();
  sel.removeAllRanges();
  sel.addRange(range);
  const hint = el.closest('.summary-body').previousElementSibling.querySelector('.summary-edit-hint');
  if (hint) { hint.textContent = 'Esc 또는 외부 클릭으로 저장'; hint.style.color = '#e09000'; }
}

function endEdit(el) {
  el.contentEditable = 'false';
  // 편집된 마크다운 저장 후 렌더링
  const md = el.innerText;
  el.dataset.md = md;
  el.innerHTML = marked.parse(md);
  const hint = el.closest('.summary-body').previousElementSibling.querySelector('.summary-edit-hint');
  if (hint) { hint.textContent = '더블클릭하여 편집'; hint.style.color = ''; }
}

