function startEdit(el) {
  if (el.nextElementSibling && el.nextElementSibling.classList.contains('summary-editor')) return;

  // 뷰어의 현재 크기 측정
  const h = el.getBoundingClientRect().height;

  const ta = document.createElement('textarea');
  ta.className = 'summary-editor';
  ta.value = el.dataset.md || '';
  // 뷰어와 동일한 높이, max-height도 동일하게
  ta.style.height = Math.max(h, 60) + 'px';
  ta.style.maxHeight = '115px';

  el.style.display = 'none';
  el.parentNode.insertBefore(ta, el.nextSibling);
  ta.focus();
  ta.setSelectionRange(ta.value.length, ta.value.length);

